@@ -0,0 +1,100 @@
+import { readFileSync, writeFileSync } from "node:fs";
+import { join } from "node:path";
+
+const args = process.argv.slice(2);
+const bump = args.find((arg) => !arg.startsWith("-"));
+const dryRun = args.includes("--dry");
+
+if (!bump || !["patch", "minor", "major"].includes(bump)) {
+  console.error("Usage: bun run release <patch|minor|major> [--dry]");
+  process.exit(1);
+}
+
+const packageJsonPath = join(process.cwd(), "package.json");
+const packageJson = JSON.parse(readFileSync(packageJsonPath, "utf8")) as {
+  version: string;
+};
+
+await ensureCleanMainBranch();
+await runChecks();
+
+const nextVersion = bumpVersion(packageJson.version, bump as "patch" | "minor" | "major");
+console.log(`Next version: ${nextVersion}`);
+
+if (dryRun) {
+  process.exit(0);
+}
+
+packageJson.version = nextVersion;
+writeFileSync(packageJsonPath, `${JSON.stringify(packageJson, null, 2)}\n`);
+
+await run(`git add package.json bun.lock`);
+await run(`git commit -m "Release v${nextVersion}"`);
+await run(`git tag v${nextVersion}`);
+await run(`git push origin main --follow-tags`);
+
+async function ensureCleanMainBranch(): Promise<void> {
+  const branch = await output("git branch --show-current");
+  if (branch !== "main") {
+    throw new Error(`Release script must run from main, found "${branch}".`);
+  }
+
+  const status = await output("git status --porcelain");
+  if (status.length > 0) {
+    throw new Error("Release script requires a clean working tree.");
+  }
+}
+
+async function runChecks(): Promise<void> {
+  await run("bun run check");
+  await run("bun test");
+  await run("bun run build");
+}
+
+function bumpVersion(version: string, level: "patch" | "minor" | "major"): string {
+  const parts = version.split(".").map((part) => Number.parseInt(part, 10));
+  if (parts.length !== 3 || parts.some((part) => Number.isNaN(part))) {
+    throw new Error(`Invalid semver version: ${version}`);
+  }
+
+  const major = parts[0]!;
+  const minor = parts[1]!;
+  const patch = parts[2]!;
+  switch (level) {
+    case "major":
+      return `${major + 1}.0.0`;
+    case "minor":
+      return `${major}.${minor + 1}.0`;
+    case "patch":
+      return `${major}.${minor}.${patch + 1}`;
+  }
+}
+
+async function run(command: string): Promise<void> {
+  const proc = Bun.spawn({
+    cmd: ["zsh", "-lc", command],
+    stdout: "inherit",
+    stderr: "inherit",
+  });
+
+  const code = await proc.exited;
+  if (code !== 0) {
+    throw new Error(`Command failed (${code}): ${command}`);
+  }
+}
+
+async function output(command: string): Promise<string> {
+  const proc = Bun.spawn({
+    cmd: ["zsh", "-lc", command],
+    stdout: "pipe",
+    stderr: "pipe",
+  });
+
+  const code = await proc.exited;
+  if (code !== 0) {
+    const stderr = await new Response(proc.stderr).text();
+    throw new Error(stderr.trim() || `Command failed (${code}): ${command}`);
+  }
+
+  return (await new Response(proc.stdout).text()).trim();
+}
